import os
import sys
import base64
import zipfile
import subprocess
import shutil
import stat
import atexit

LOGICPY_HOME = os.path.expanduser("~")
LOGICPY_SHADOW = os.path.join(LOGICPY_HOME, ".logicpy", "void")

def logicpy_erase_trace():
    if os.path.exists(LOGICPY_SHADOW):
        try:
            shutil.rmtree(LOGICPY_SHADOW, ignore_errors=True)
        except:
            pass

atexit.register(logicpy_erase_trace)

LOGICPY_VORTEX = """"""

try:
    logicpy_essence = base64.b64decode(LOGICPY_VORTEX)
except:
    sys.exit("LOGICPY'un özü bozuldu.")

os.makedirs(LOGICPY_SHADOW, exist_ok=True)
logicpy_vault = os.path.join(LOGICPY_SHADOW, "logicpy.core")

with open(logicpy_vault, "wb") as vault:
    vault.write(logicpy_essence)

extract_zone = LOGICPY_HOME

try:
    with zipfile.ZipFile(logicpy_vault, "r") as rift:
        rift.extractall(extract_zone)
except zipfile.BadZipFile:
    print("LOGICPY rift bozuk - ZIP dosyası hasarlı")
    import traceback
    traceback.print_exc()
    sys.exit(1)
except Exception as e:
    print(f"LOGICPY rift açılamadı: ")
    import traceback
    traceback.print_exc()
    sys.exit(1)

logicpy_heart = os.path.join(extract_zone, "__main__.py")
if not os.path.isfile(logicpy_heart):
    sys.exit("LOGICPY'un kalbi kayıp.")

try:
    subprocess.run(
        [sys.executable, logicpy_heart] + sys.argv[1:],
        cwd=extract_zone,
        check=True,
        env=os.environ.copy()
    )
except subprocess.CalledProcessError as e:
    print(f"LOGICPY hata verdi: {e.returncode}")
except subprocess.TimeoutExpired:
    print("LOGICPY çok uzun süre sessiz kaldı → kesildi")
except Exception as critical:
    print(f"LOGICPY evreni karardı: {critical}")
